// ============================================================
// Mini's IPA Repo — Main Entry Point
// ============================================================

import './style.css';

import type { AppData, AppState, Category, RawManifest, SearchResult } from './types';
import { CATEGORIES } from './types';
import { CONFIG } from './config';
import {
    sanitizeTintColor,
    formatSize,
    inferCategory,
    generateId,
    normalizePermissions,
    debounce,
    idbGet,
    idbSet,
    escapeHtml,
    escapeAttr,
} from './utils';
import { fuzzySearch, getWordStartIndices, highlightMatches } from './search';
import { VirtualScroll } from './virtual-scroll';
import { createCardNode, bindCard, handleDownload, setupFeaturedCard, setupImagePriorities } from './card';
import { openAppModal, closeAppModal, handleHashRoute, setupPopstateHandler } from './modal';
import { showToast } from './toast';
import { initHeroGL } from './hero';
import { setupPWA, setupInstallPrompt, setupOnlineOffline, updateAppBadge, cleanupPWA, clearAllCaches } from './pwa';

// ── State ──────────────────────────────────────────────────

const state: AppState = {
    apps: [],
    filteredApps: [],
    searchTerm: '',
    activeCategory: 'all',
    sortMode: 'recent',
    isLoading: true,
    isOnline: navigator.onLine,
    modalOpen: false,
    modalScrollY: 0,
    lastOpenedCardId: null,
    modalHistoryPushed: false,
    deferredInstallPrompt: null,
    renderGeneration: 0,
    recentSearches: [],
    searchOverlayOpen: false,
    developerIndex: new Map(),
};

let virtualScroll: VirtualScroll | null = null;
let heroCleanup: (() => void) | null = null;
let scrollTopObserver: IntersectionObserver | null = null;
let copyResetTimer: ReturnType<typeof setTimeout> | null = null;
let searchResults: SearchResult[] = [];
// Companion map for O(1) lookups in the bindCard callback (avoids O(n) .find() on scroll)
let searchResultsMap = new Map<string, SearchResult>();
// 027: saved scroll position from before the search overlay was opened
let _searchOverlayScrollY = 0;

// Change detection for filterAndSortApps — skip expensive work if nothing changed
let prevSearchTerm = '';
let prevCategory = 'all';
let prevSortMode = 'recent';

// ── Initialization ─────────────────────────────────────────

document.addEventListener('DOMContentLoaded', async () => {
    try {
        setupEventListeners();
        setupGlobalErrorHandling();
        setupPWA(state, handleDataRefresh);
        setupInstallPrompt(state);
        setupOnlineOffline(state);
        setupPopstateHandler(state);
        showLoadingState();

        // Defer hero WebGL init off the critical path
        // Polyfill uses 100ms so the browser paints first before WebGL setup starts
        const deferInit = window.requestIdleCallback ?? ((cb: () => void) => setTimeout(cb, 100));
        deferInit(() => initHero());

        // Load recent searches from IndexedDB
        const saved = await idbGet<string[]>('searches', 'recent');
        if (saved) state.recentSearches = saved;

        state.apps = await loadAppData();
        state.isLoading = false;
        buildDeveloperIndex();

        if (state.apps.length === 0) {
            showErrorState('No apps available in this repository');
        } else {
            updateAppCount(state.apps.length);
            setupFeatured();
            updateCategoryPillCounts();
            setupImagePriorities(state.apps);
            initVirtualScroll();
            filterAndSortApps(true);
            handleHashRoute(state);
            handleStartupParams();
            updateAppBadge(state.apps);
            setupScrollToTop();
        }
    } catch (error) {
        console.error('Initialization error:', error);
        showErrorState((error as Error).message ?? 'Failed to initialize');
    }
});

// ── Data Loading ───────────────────────────────────────────

/**
 * ERR-001: Fetch with exponential-backoff retry for transient network errors.
 * Retries ONLY on network-level failures (fetch throws), not on HTTP error
 * responses (4xx/5xx) — those are deterministic and retrying won't help.
 * AbortError (user-initiated timeout) is never retried.
 */
async function fetchWithRetry(
    url: string,
    init: RequestInit,
    maxAttempts = 3,
): Promise<Response> {
    let lastErr: unknown;
    for (let attempt = 0; attempt < maxAttempts; attempt++) {
        try {
            return await fetch(url, init);
        } catch (err) {
            if ((err as Error).name === 'AbortError') throw err; // don't retry timeouts
            lastErr = err;
            if (attempt < maxAttempts - 1) {
                await new Promise((r) => setTimeout(r, 1000 * 2 ** attempt)); // 1s, 2s, 4s
            }
        }
    }
    throw lastErr;
}

async function loadAppData(): Promise<AppData[]> {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), CONFIG.FETCH_TIMEOUT);

    const appGrid = document.getElementById('appGrid');
    if (appGrid) appGrid.setAttribute('aria-busy', 'true');

    // UX-005: notify user if the fetch is taking longer than SLOW_LOAD_THRESHOLD
    const slowLoadTimer = setTimeout(() => showToast('Loading apps…', 'info'), CONFIG.SLOW_LOAD_THRESHOLD);

    try {
        const response = await fetchWithRetry(CONFIG.API_ENDPOINT, {
            signal: controller.signal,
            cache: 'no-cache',
        });

        if (!response.ok) throw new Error(`HTTP ${response.status}: ${response.statusText}`);

        const ct = response.headers.get('content-type') ?? '';
        if (!ct.includes('json')) {
            throw new Error(`Unexpected content type "${ct}" — verify the API endpoint URL`);
        }

        let data: RawManifest;
        try {
            data = await response.json();
        } catch {
            // UX-007: include HTTP status and content-type for easier debugging
            throw new Error(
                `Data corruption: Unable to parse app manifest (HTTP ${response.status}, Content-Type: ${response.headers.get('content-type') ?? 'unknown'}).`,
            );
        }

        if (!data?.apps || !Array.isArray(data.apps)) {
            throw new Error('Invalid manifest structure');
        }

        return data.apps
            .filter((app) => app.versions?.length > 0)
            .map((app, idx) => {
                const v = app.versions[0];
                const category = inferCategory(app.bundleIdentifier ?? '');
                return {
                    id: generateId(app.bundleIdentifier, idx),
                    name: app.name ?? 'Unknown App',
                    bundleId: app.bundleIdentifier ?? '',
                    developer: app.developerName ?? 'Unknown',
                    description: app.localizedDescription ?? '',
                    icon: app.iconURL ?? CONFIG.FALLBACK_ICON,
                    version: v.version ?? 'Unknown',
                    date: v.date ?? '',
                    downloadUrl: v.downloadURL ?? '',
                    category,
                    size: formatSize(v.size),
                    sizeBytes: v.size ?? 0,
                    changelog: v.localizedDescription ?? '',
                    tintColor: sanitizeTintColor(app.tintColor),
                    subtitle: app.subtitle ?? '',
                    minimumOS: v.minOSVersion ?? CONFIG.DEFAULT_MIN_OS,
                    permissions: normalizePermissions(app.permissions ?? []),
                    screenshots: app.screenshotURLs ?? [],
                    _searchName: (app.name ?? '').toLowerCase(),
                    _searchDev: (app.developerName ?? '').toLowerCase(),
                    _searchDesc: (app.localizedDescription ?? '').toLowerCase(),
                    _wordStartsName: getWordStartIndices((app.name ?? '').toLowerCase()),
                    _wordStartsDev: getWordStartIndices((app.developerName ?? '').toLowerCase()),
                    _wordStartsDesc: getWordStartIndices((app.localizedDescription ?? '').toLowerCase()),
                };
            });
    } catch (error) {
        if ((error as Error).name === 'AbortError') {
            throw new Error('Request timeout — please check your connection');
        }
        // 010: TypeError is thrown by fetch() for network-level failures (DNS, offline,
        // CORS). Wrap with a user-friendly message instead of exposing the raw TypeError.
        if (error instanceof TypeError) {
            throw new Error('Network error — check your connection and try again');
        }
        throw error;
    } finally {
        clearTimeout(timeoutId);
        clearTimeout(slowLoadTimer);
        if (appGrid) appGrid.removeAttribute('aria-busy');
    }
}

// ── Developer Index ────────────────────────────────────────

function buildDeveloperIndex(): void {
    state.developerIndex = new Map();
    for (const app of state.apps) {
        // Lowercase key makes lookups case-insensitive — "Spotify AB" and
        // "spotify ab" from different manifest entries map to the same bucket.
        const key = app.developer.toLowerCase();
        const existing = state.developerIndex.get(key);
        if (existing) {
            existing.push(app);
        } else {
            state.developerIndex.set(key, [app]);
        }
    }
}

// ── Filtering & Sorting ────────────────────────────────────

function filterAndSortApps(force = false): void {
    // Skip expensive work if nothing changed
    if (!force &&
        state.searchTerm === prevSearchTerm &&
        state.activeCategory === prevCategory &&
        state.sortMode === prevSortMode) {
        return;
    }
    prevSearchTerm = state.searchTerm;
    prevCategory = state.activeCategory;
    prevSortMode = state.sortMode;

    state.renderGeneration++;

    if (state.searchTerm) {
        // Filter by category first (cheaper) so fuzzySearch only scores relevant apps
        const pool =
            state.activeCategory === 'all'
                ? state.apps
                : state.apps.filter((a) => a.category === state.activeCategory);
        searchResults = fuzzySearch(state.searchTerm, pool);
        searchResultsMap = new Map(searchResults.map((r) => [r.app.id, r]));
        state.filteredApps = searchResults.map((r) => r.app);
    } else {
        searchResults = [];
        searchResultsMap = new Map();
        state.filteredApps = state.apps.filter((app) => {
            return (
                state.activeCategory === 'all' ||
                app.category === state.activeCategory
            );
        });
    }

    // Sort
    if (!state.searchTerm) {
        // Only sort by user preference when not searching (search has its own ranking)
        if (state.sortMode === 'alpha') {
            state.filteredApps.sort((a, b) => a.name.localeCompare(b.name));
        } else {
            state.filteredApps.sort((a, b) => (b.date > a.date ? 1 : b.date < a.date ? -1 : 0));
        }
    }

    // Update virtual scroll
    virtualScroll?.setItems(state.filteredApps);
    announceResultsCount();
    updateCategoryFilterIndicator();

    // UX-002: show empty state when a category filter returns zero apps
    const grid = document.getElementById('appGrid');
    let emptyEl = document.getElementById('emptyFilterState');
    if (state.filteredApps.length === 0 && !state.searchTerm && state.activeCategory !== 'all') {
        if (!emptyEl && grid) {
            emptyEl = document.createElement('div');
            emptyEl.id = 'emptyFilterState';
            emptyEl.className = 'empty-filter-state';
            emptyEl.setAttribute('role', 'status');
            emptyEl.innerHTML = `
                <div class="empty-filter-icon" aria-hidden="true"></div>
                <p>No ${escapeHtml(state.activeCategory)} apps yet</p>
                <button type="button" class="empty-filter-clear">Show all apps</button>
            `;
            grid.parentElement?.insertBefore(emptyEl, grid.nextSibling);
            // UX-002: move focus to the clear button so keyboard users don't have to tab to it
            (emptyEl.querySelector('.empty-filter-clear') as HTMLElement | null)?.focus();
            emptyEl.querySelector('.empty-filter-clear')?.addEventListener('click', () => {
                state.activeCategory = 'all';
                document.querySelectorAll('.category-pill').forEach((p) => {
                    const isAll = (p as HTMLElement).dataset.category === 'all';
                    p.classList.toggle('active', isAll);
                    p.setAttribute('aria-selected', String(isAll));
                    p.setAttribute('tabindex', isAll ? '0' : '-1');
                });
                document.getElementById('appGrid')?.setAttribute('aria-labelledby', 'pill-all');
                filterAndSortApps(true);
            });
        }
    } else {
        emptyEl?.remove();
    }
}

function announceResultsCount(): void {
    const el = document.getElementById('searchResultsCount');
    if (!el) return;
    const total = state.filteredApps.length;
    const allTotal = state.apps.length;

    if (!state.searchTerm && state.activeCategory === 'all') {
        el.textContent = `${allTotal} apps available, showing all ${total}`;
    } else if (total === 0) {
        el.textContent = 'No apps found';
    } else {
        el.textContent = `${allTotal} apps available, filtered to ${total}`;
    }
}

// ── Virtual Scroll Setup ───────────────────────────────────

function initVirtualScroll(): void {
    const container = document.getElementById('appGrid');
    if (!container) return;
    container.innerHTML = '';

    virtualScroll = new VirtualScroll(container, {
        createCardNode,
        bindCard: (el, app) => {
            // O(1) lookup via companion map (searchResults.find() would be O(n))
            const sr = searchResultsMap.get(app.id);
            bindCard(el, app, sr?.nameMatches);
        },
        onCardClick: (appId) => openAppModal(appId, state),
    });

    // Download button delegation
    container.addEventListener('click', (e) => {
        const btn = (e.target as HTMLElement).closest('.card-get-btn') as HTMLElement | null;
        if (btn) {
            e.stopPropagation();
            const id = btn.dataset.id;
            if (id) handleDownload(id, state.apps, state.isOnline);
        }
    });

    // Long-press / right-click context menu
    setupCardContextMenu(container);
}

// ── Featured App ───────────────────────────────────────────

function setupFeatured(): void {
    const app = state.apps.find((a) => a.bundleId === CONFIG.FEATURED_BUNDLE_ID);
    if (!app) {
        // UX-003: surface misconfigured FEATURED_BUNDLE_ID without throwing
        console.debug('[featured] Bundle ID not found in manifest:', CONFIG.FEATURED_BUNDLE_ID);
        return;
    }

    const section = document.getElementById('featuredSection');
    const card = document.getElementById('featuredCard');
    if (!section || !card) return;

    setupFeaturedCard(app, section, card, (id) => openAppModal(id, state));

    // Featured download button
    const getBtn = card.querySelector('.featured-get-btn');
    getBtn?.addEventListener('click', (e) => {
        e.stopPropagation();
        handleDownload(app.id, state.apps, state.isOnline);
    });
}

// ── Hero ───────────────────────────────────────────────────

function initHero(): void {
    const canvas = document.getElementById('heroCanvas') as HTMLCanvasElement | null;
    const heroStatus = document.getElementById('heroStatus');
    if (canvas) {
        heroCleanup = initHeroGL(canvas);
        // If WebGL failed, the CSS fallback (conic-gradient) is already active.
        // A11y1: announce hero animation state so screen reader users know
        // the page loaded correctly regardless of WebGL support.
        if (heroCleanup) {
            canvas.classList.add('active');
            if (heroStatus) heroStatus.textContent = 'Animated hero loaded';
        } else {
            if (heroStatus) heroStatus.textContent = 'Hero animation not supported — static gradient shown';
        }
    }
}

// ── Category Pills ─────────────────────────────────────────

function updateCategoryPillCounts(): void {
    const counts: Record<string, number> = { all: state.apps.length };
    for (const app of state.apps) {
        counts[app.category] = (counts[app.category] || 0) + 1;
    }

    document.querySelectorAll('.category-pill').forEach((pill) => {
        const cat = (pill as HTMLElement).dataset.category;
        if (!cat) return;
        const count = counts[cat];
        if (count === undefined) return;

        let badge = pill.querySelector('.category-count');
        if (!badge) {
            badge = document.createElement('span');
            badge.className = 'category-count';
            badge.setAttribute('aria-hidden', 'true');
            pill.appendChild(badge);
        }
        badge.textContent = String(count);
    });
}

// ── Category Filter Indicator ──────────────────────────────

/** UX-010: show/hide a "clear filter" chip when a non-all category is active */
function updateCategoryFilterIndicator(): void {
    const filtersEl = document.getElementById('categoryFilters');
    if (!filtersEl) return;

    const existingChip = document.getElementById('activeCategoryChip');
    if (state.activeCategory !== 'all') {
        if (!existingChip) {
            const chip = document.createElement('button');
            chip.type = 'button';
            chip.id = 'activeCategoryChip';
            chip.className = 'active-filter-chip';
            chip.setAttribute('aria-label', `Clear ${state.activeCategory} filter`);
            chip.innerHTML = `${escapeHtml(state.activeCategory)} <svg width="10" height="10" viewBox="0 0 10 10" fill="none" aria-hidden="true"><path d="M2 2l6 6M8 2l-6 6" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"/></svg>`;
            chip.addEventListener('click', () => {
                state.activeCategory = 'all';
                document.querySelectorAll('.category-pill').forEach((p) => {
                    const isAll = (p as HTMLElement).dataset.category === 'all';
                    p.classList.toggle('active', isAll);
                    p.setAttribute('aria-selected', String(isAll));
                    p.setAttribute('tabindex', isAll ? '0' : '-1');
                });
                document.getElementById('appGrid')?.setAttribute('aria-labelledby', 'pill-all');
                filterAndSortApps(true);
            });
            filtersEl.parentElement?.insertBefore(chip, filtersEl.nextSibling);
        } else {
            // Update label if category changed
            existingChip.setAttribute('aria-label', `Clear ${state.activeCategory} filter`);
            existingChip.innerHTML = `${escapeHtml(state.activeCategory)} <svg width="10" height="10" viewBox="0 0 10 10" fill="none" aria-hidden="true"><path d="M2 2l6 6M8 2l-6 6" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"/></svg>`;
        }
    } else {
        existingChip?.remove();
    }
}

// ── App Count ──────────────────────────────────────────────

function updateAppCount(count: number): void {
    const el = document.getElementById('appCountText');
    if (!el) return;
    const next = `${count} Apps`;
    if (el.textContent === next) return;
    el.textContent = next;
    // UX-011: briefly animate the badge to signal the number changed.
    // Double-rAF lets the browser commit the class removal before re-adding it,
    // restarting the animation without a synchronous layout reflow (offsetWidth read).
    el.classList.remove('count-updated');
    requestAnimationFrame(() => requestAnimationFrame(() => el.classList.add('count-updated')));
}

// ── Search Overlay ─────────────────────────────────────────

function openSearchOverlay(): void {
    // 027: save scroll position so closeSearchOverlay() can restore it.
    _searchOverlayScrollY = window.scrollY;
    state.searchOverlayOpen = true;
    const overlay = document.getElementById('searchOverlay');
    const input = document.getElementById('searchOverlayInput') as HTMLInputElement | null;
    if (!overlay || !input) return;

    overlay.classList.add('active');
    document.body.classList.add('search-overlay-open');
    document.getElementById('searchBox')?.setAttribute('aria-expanded', 'true');
    input.value = state.searchTerm;
    input.focus();

    // Render recent searches and any existing results
    renderRecentSearches();
    renderOverlayResults();
}

function closeSearchOverlay(): void {
    state.searchOverlayOpen = false;
    const overlay = document.getElementById('searchOverlay');
    if (!overlay) return;

    // Blur the overlay input to prevent focus loops
    const overlayInput = document.getElementById('searchOverlayInput') as HTMLInputElement | null;
    overlayInput?.blur();

    overlay.classList.remove('active');
    document.body.classList.remove('search-overlay-open');
    document.getElementById('searchBox')?.setAttribute('aria-expanded', 'false');

    // Clear inline results so they don't flash on next open
    const resultsContainer = document.getElementById('searchOverlayResults');
    if (resultsContainer) resultsContainer.innerHTML = '';
    document.getElementById('recentSearches')?.classList.remove('hidden');

    // Sync the search term to the main search box so the user sees what's active
    const searchBox = document.getElementById('searchBox') as HTMLInputElement | null;
    if (searchBox) {
        searchBox.value = state.searchTerm;
        searchBox.placeholder = state.searchTerm ? '' : 'Search apps...';
    }

    // Show/hide clear button
    updateSearchClearButton();

    // 027: restore scroll position — the overlay may have changed body scroll
    window.scrollTo({ top: _searchOverlayScrollY, behavior: 'instant' as ScrollBehavior });
}

function renderRecentSearches(): void {
    const container = document.getElementById('recentSearches');
    if (!container) return;

    if (state.recentSearches.length === 0) {
        container.innerHTML = '';
        return;
    }

    // escapeAttr for the data-term attribute (escapes &, ", ', <, >)
    // escapeHtml for the visible text (escapes &, <, >)
    container.innerHTML = state.recentSearches
        .map(
            (term) =>
                `<button type="button" class="recent-search-pill" data-term="${escapeAttr(term)}">${escapeHtml(term)}</button>`,
        )
        .join('');
}

function updateSearchClearButton(): void {
    const btn = document.getElementById('searchClearBtn');
    const shortcut = document.querySelector('.search-shortcut') as HTMLElement | null;
    if (btn) {
        btn.classList.toggle('visible', state.searchTerm.length > 0);
    }
    // Hide keyboard shortcut hint when search is active
    if (shortcut) {
        shortcut.style.display = state.searchTerm.length > 0 ? 'none' : '';
    }
}

function clearSearch(): void {
    state.searchTerm = '';
    const searchBox = document.getElementById('searchBox') as HTMLInputElement | null;
    if (searchBox) {
        searchBox.value = '';
        searchBox.placeholder = 'Search apps...';
    }
    filterAndSortApps();
    updateSearchClearButton();
}

function addRecentSearch(term: string): void {
    if (!term || term.length < 2) return;
    const termLower = term.toLowerCase();
    state.recentSearches = [
        term,
        ...state.recentSearches.filter((t) => t.toLowerCase() !== termLower),
    ].slice(0, CONFIG.MAX_RECENT_SEARCHES);
    idbSet('searches', 'recent', state.recentSearches).catch(() => {});
}

// ── Overlay Inline Results ─────────────────────────────────

function renderOverlayResults(): void {
    try {
        _renderOverlayResultsInner();
    } catch (err) {
        // UX-001: if result rendering throws, show a toast rather than leaving a blank overlay
        console.error('[renderOverlayResults] Render failed:', err);
        showToast('Search display error — try again', 'error');
    }
}

function _renderOverlayResultsInner(): void {
    const container = document.getElementById('searchOverlayResults');
    const recentsEl = document.getElementById('recentSearches');
    if (!container) return;

    const term = state.searchTerm;

    // No query — show recents, hide results
    if (!term) {
        container.innerHTML = '';
        recentsEl?.classList.remove('hidden');
        return;
    }

    // Hide recents when showing results
    recentsEl?.classList.add('hidden');

    // Reuse the searchResults already computed by filterAndSortApps()
    // to avoid running fuzzySearch() a second time.
    const results = searchResults;

    if (results.length === 0) {
        // Wrap in <li> — container is now a <ul> so only list items are valid children.
        container.innerHTML = `
            <li class="search-overlay-no-results" role="status">
                <div class="search-overlay-no-results-icon" aria-hidden="true"></div>
                <p>No apps found for "<strong>${escapeHtml(term)}</strong>"</p>
            </li>`;
        return;
    }

    // Render at most 20 results for performance
    const maxResults = 20;
    const slice = results.slice(0, maxResults);

    // Each result is <li><button> so the native list item role is provided by <li>
    // and the interactive element is the <button>. Previously role="listitem" was
    // placed directly on the <button>, which overrides its native button role and
    // causes screen readers to announce it incorrectly.
    container.innerHTML = slice.map((r) => {
        const nameHtml = highlightMatches(r.app.name, r.nameMatches);
        const escapedDev = escapeHtml(r.app.developer);
        // UX-009: show category badge and truncated description snippet
        const snippet = r.app.description.length > 60
            ? escapeHtml(r.app.description.slice(0, 60)) + '…'
            : escapeHtml(r.app.description);
        const cat = escapeHtml(r.app.category);
        return `<li><button type="button" class="search-result-item" data-app-id="${escapeAttr(r.app.id)}">
            <img class="search-result-icon" src="${escapeAttr(r.app.icon)}" alt="" width="44" height="44" loading="lazy" />
            <div class="search-result-info">
                <div class="search-result-name">${nameHtml}</div>
                <div class="search-result-dev">${escapedDev}${cat ? ` <span class="search-result-cat" aria-hidden="true">${cat}</span>` : ''}</div>
                ${snippet ? `<div class="search-result-desc">${snippet}</div>` : ''}
            </div>
            <span class="search-result-get" aria-hidden="true">GET</span>
        </button></li>`;
    }).join('');

    // Show count if truncated
    if (results.length > maxResults) {
        container.insertAdjacentHTML('beforeend',
            `<li class="search-overlay-no-results" style="padding:var(--s3) var(--s4);font-size:0.8em;" aria-hidden="true">
                and ${results.length - maxResults} more…
            </li>`);
    }

    // A11Y-003: update live region so screen readers announce the result count
    const liveRegion = document.getElementById('searchOverlayResultCount');
    if (liveRegion) {
        const shown = Math.min(results.length, maxResults);
        liveRegion.textContent = results.length === 0
            ? 'No results found'
            : `${results.length} result${results.length !== 1 ? 's' : ''} found, showing ${shown}`;
    }
}


// ── Scroll to Top ──────────────────────────────────────────

function setupScrollToTop(): void {
    const btn = document.getElementById('scrollTopBtn');
    const hero = document.querySelector('.hero');
    if (!btn || !hero) return;

    scrollTopObserver = new IntersectionObserver(
        (entries) => {
            const isVisible = entries[0].isIntersecting;
            btn.classList.toggle('visible', !isVisible);
            btn.setAttribute('aria-hidden', String(isVisible));
        },
        { threshold: 0 },
    );
    scrollTopObserver.observe(hero);

    btn.addEventListener('click', () => {
        const reduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
        window.scrollTo({ top: 0, behavior: reduced ? 'auto' : 'smooth' });
    });
}

// ── Loading / Error States ─────────────────────────────────

function showLoadingState(): void {
    const grid = document.getElementById('appGrid');
    if (!grid) return;
    grid.setAttribute('aria-busy', 'true');
    grid.innerHTML = Array(6)
        .fill(0)
        .map(
            (_, i) => `
        <div class="skeleton-card stagger-${(i % 3) + 1}" aria-hidden="true">
            <div class="skeleton skeleton-icon"></div>
            <div class="skeleton-lines">
                <div class="skeleton skeleton-text short"></div>
                <div class="skeleton skeleton-text medium"></div>
            </div>
            <div class="skeleton skeleton-button"></div>
        </div>`,
        )
        .join('');
}

function showErrorState(msg: string): void {
    const grid = document.getElementById('appGrid');
    if (!grid) return;
    grid.removeAttribute('aria-busy');
    // Note: no onclick attribute — inline event handlers are blocked by the
    // page's CSP (script-src 'self' without 'unsafe-inline'). Attach listener
    // imperatively after setting innerHTML instead.
    grid.innerHTML = `
        <div class="error-state">
            <div class="error-icon" aria-hidden="true">
                <svg width="48" height="48" viewBox="0 0 48 48" fill="none"><circle cx="24" cy="24" r="22" stroke="currentColor" stroke-width="2"/><path d="M24 14v12M24 32v2" stroke="currentColor" stroke-width="2.5" stroke-linecap="round"/></svg>
            </div>
            <h3>Something went wrong</h3>
            <p></p>
            <button type="button" class="retry-btn">Try Again</button>
        </div>
    `;
    const p = grid.querySelector('.error-state p');
    if (p) p.textContent = String(msg);
    const retryBtn = grid.querySelector<HTMLButtonElement>('.retry-btn');
    if (retryBtn) retryBtn.addEventListener('click', () => location.reload());
}

// ── Data Refresh (from SW) ─────────────────────────────────

let lastRefreshTime = 0;
const REFRESH_COOLDOWN = 10_000; // 10s minimum between refreshes
// C3: atomic in-flight flag prevents concurrent refreshes from racing past the
// cooldown check. Set synchronously before any await, cleared in finally.
let _refreshInFlight = false;

async function handleDataRefresh(): Promise<void> {
    if (_refreshInFlight) {
        console.debug('[handleDataRefresh] Dropped: a refresh is already in progress.');
        return;
    }
    const now = Date.now();
    if (now - lastRefreshTime < REFRESH_COOLDOWN) {
        console.debug('[handleDataRefresh] Dropped: within cooldown window.');
        return;
    }
    _refreshInFlight = true;
    lastRefreshTime = now;

    try {
        const newApps = await loadAppData();
        state.apps = newApps;
        buildDeveloperIndex();
        // Rebuild searchResultsMap so new apps get correct highlight ranges (M4)
        if (state.searchTerm) {
            const pool = state.activeCategory === 'all'
                ? state.apps
                : state.apps.filter((a) => a.category === state.activeCategory);
            const { fuzzySearch: fsearch } = await import('./search');
            const results = fsearch(state.searchTerm, pool);
            searchResultsMap = new Map(results.map((r) => [r.app.id, r]));
        }
        updateAppCount(newApps.length);
        setupFeatured();
        updateCategoryPillCounts();
        filterAndSortApps(true);
        showToast('App list updated', 'info');
    } catch (err) {
        // M1: log background refresh errors to console for debugging
        console.warn('[handleDataRefresh] Background refresh failed:', err);
    } finally {
        _refreshInFlight = false;
    }
}

// ── Copy URL Handler ───────────────────────────────────────

async function handleCopyUrl(): Promise<void> {
    const btn = document.getElementById('btn-copy-url');
    const label = document.getElementById('copyUrlLabel');

    try {
        await navigator.clipboard.writeText(CONFIG.API_ENDPOINT);
    } catch {
        // Clipboard API unavailable (insecure context or permission denied)
        showToast(`Copy failed — URL: ${CONFIG.API_ENDPOINT}`, 'warning');
        return;
    }

    showToast('Manifest URL copied', 'success');
    if (btn && label) {
        label.textContent = 'Copied!';
        btn.classList.add('copied');
        if (copyResetTimer) clearTimeout(copyResetTimer);
        copyResetTimer = setTimeout(() => {
            copyResetTimer = null;
            label.textContent = 'Copy URL';
            btn.classList.remove('copied');
        }, CONFIG.COPY_RESET_DURATION);
    }
}

// ── Startup URL Params (shortcuts + share target) ──────────

/**
 * Reads query parameters written by manifest shortcuts and the share_target
 * handler, then acts on them:
 *   ?action=search           → open search overlay
 *   ?category=Music|Video…   → activate category filter
 *   ?search=X  ?text=X  ?name=X  → pre-fill and open search overlay
 *
 * The URL is cleaned up immediately so refreshes / history entries don't
 * re-trigger the action.
 */
function handleStartupParams(): void {
    const params = new URLSearchParams(window.location.search);
    if (!params.toString()) return;

    // Strip query params from the URL, keep any hash fragment
    history.replaceState(null, '', window.location.pathname + window.location.hash);

    // Share-target text or explicit search param
    const searchText = params.get('search') ?? params.get('text') ?? params.get('name');
    if (searchText?.trim()) {
        const term = searchText.trim();
        state.searchTerm = term.toLowerCase();
        filterAndSortApps();
        openSearchOverlay();
        const input = document.getElementById('searchOverlayInput') as HTMLInputElement | null;
        if (input) {
            input.value = term;
            renderOverlayResults();
        }
        return;
    }

    // ?action=search shortcut
    if (params.get('action') === 'search') {
        openSearchOverlay();
        return;
    }

    // ?category=X shortcut
    const category = params.get('category');
    if (category && (CATEGORIES as readonly string[]).includes(category)) {
        state.activeCategory = category as Category;
        document.getElementById('categoryFilters')
            ?.querySelectorAll('.category-pill')
            .forEach((p) => {
                const isActive = (p as HTMLElement).dataset.category === category;
                p.classList.toggle('active', isActive);
                p.setAttribute('aria-selected', String(isActive));
                p.setAttribute('tabindex', isActive ? '0' : '-1');
            });
        // Sync tabpanel label with activated category
        document.getElementById('appGrid')?.setAttribute('aria-labelledby', `pill-${category}`);
        filterAndSortApps(true);
    }
}

// ── Event Listeners ────────────────────────────────────────

function setupEventListeners(): void {
    // Main search box — opens overlay on focus (with guard against re-open loops)
    const searchBox = document.getElementById('searchBox') as HTMLInputElement | null;
    searchBox?.addEventListener('focus', () => {
        if (!state.searchOverlayOpen) {
            openSearchOverlay();
        }
        // Blur the readonly input so it doesn't hold focus
        searchBox.blur();
    });

    // Clear search button
    document.getElementById('searchClearBtn')?.addEventListener('click', (e) => {
        e.stopPropagation(); // Don't trigger search box focus
        clearSearch();
    });

    // Search overlay input
    const overlayInput = document.getElementById('searchOverlayInput') as HTMLInputElement | null;
    // Debounced search stored at function scope so Enter/Escape/Close can cancel it
    const debouncedSearch = debounce((value: unknown) => {
        state.searchTerm = (value as string).toLowerCase().trim();
        filterAndSortApps();
        renderOverlayResults();
    }, CONFIG.SEARCH_DEBOUNCE);

    if (overlayInput) {
        overlayInput.addEventListener('input', (e) => {
            debouncedSearch((e.target as HTMLInputElement).value);
        });

        overlayInput.addEventListener('keydown', (e) => {
            if (e.key === 'Escape') {
                debouncedSearch.cancel();
                // Use the raw input value so recent searches preserve original casing
                // (state.searchTerm is always lowercased, so "Spotify" → "spotify").
                addRecentSearch(overlayInput.value.trim() || state.searchTerm);
                closeSearchOverlay();
            }
            if (e.key === 'Enter') {
                e.preventDefault();
                debouncedSearch.cancel();
                // Immediately apply the current input value (skip debounce wait)
                const rawVal = overlayInput.value.trim();
                state.searchTerm = rawVal.toLowerCase();
                filterAndSortApps();
                addRecentSearch(rawVal || state.searchTerm);
                closeSearchOverlay();
            }
        });
    }

    // Search overlay close button
    document.getElementById('searchOverlayClose')?.addEventListener('click', () => {
        debouncedSearch.cancel();
        addRecentSearch(overlayInput?.value.trim() || state.searchTerm);
        closeSearchOverlay();
    });

    // Search overlay backdrop
    document.getElementById('searchOverlay')?.addEventListener('click', (e) => {
        if (e.target === e.currentTarget) {
            debouncedSearch.cancel();
            addRecentSearch(overlayInput?.value.trim() || state.searchTerm);
            closeSearchOverlay();
        }
    });

    // Recent search pills
    document.getElementById('recentSearches')?.addEventListener('click', (e) => {
        const pill = (e.target as HTMLElement).closest('.recent-search-pill') as HTMLElement | null;
        if (!pill) return;
        const term = pill.dataset.term;
        if (!term) return;
        const input = document.getElementById('searchOverlayInput') as HTMLInputElement | null;
        if (input) input.value = term;
        state.searchTerm = term.toLowerCase();
        filterAndSortApps();
        renderOverlayResults();
    });

    // Search overlay result clicks — open modal and close overlay
    document.getElementById('searchOverlayResults')?.addEventListener('click', (e) => {
        const item = (e.target as HTMLElement).closest('.search-result-item') as HTMLElement | null;
        if (!item) return;
        const appId = item.dataset.appId;
        if (!appId) return;
        addRecentSearch(overlayInput?.value.trim() || state.searchTerm);
        closeSearchOverlay();
        openAppModal(appId, state);
    });

    // Global keyboard shortcuts
    document.addEventListener('keydown', (e) => {
        // CMD+K (Mac) or Ctrl+K (Win) → open search
        if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
            e.preventDefault();
            openSearchOverlay();
            return;
        }

        const active = document.activeElement;
        const isInput =
            active instanceof HTMLInputElement ||
            active instanceof HTMLTextAreaElement ||
            (active as HTMLElement)?.isContentEditable;

        if (e.key === '/' && !state.modalOpen && !state.searchOverlayOpen && !isInput) {
            e.preventDefault();
            openSearchOverlay();
        }

        // ? → keyboard shortcuts panel
        if (e.key === '?' && !state.modalOpen && !state.searchOverlayOpen && !isInput) {
            e.preventDefault();
            openShortcutsPanel();
        }

        // Home → scroll to top
        if (e.key === 'Home' && !state.modalOpen && !state.searchOverlayOpen && !isInput) {
            e.preventDefault();
            const reduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
            window.scrollTo({ top: 0, behavior: reduced ? 'auto' : 'smooth' });
        }

        if (e.key === 'Escape') {
            if (isShortcutsPanelOpen()) { closeShortcutsPanel(); return; }
            if (isCtxMenuVisible()) { hideCtxMenu(); return; }
            if (state.modalOpen) { closeAppModal(false, state); }
        }
    });

    // Category pills with ink ripple
    const categoryFilters = document.getElementById('categoryFilters');
    if (categoryFilters) {
        categoryFilters.addEventListener('click', (e) => {
            const pill = (e.target as HTMLElement).closest('.category-pill') as HTMLElement | null;
            if (!pill) return;

            // Ink ripple effect
            const rect = pill.getBoundingClientRect();
            const ripple = document.createElement('span');
            ripple.className = 'pill-ripple';
            ripple.style.left = `${e.clientX - rect.left}px`;
            ripple.style.top = `${e.clientY - rect.top}px`;
            pill.appendChild(ripple);
            // Also handle animationcancel: if prefers-reduced-motion suppresses
            // the animation, animationend may never fire, leaking the span.
            const removeRipple = () => ripple.remove();
            ripple.addEventListener('animationend', removeRipple, { once: true });
            ripple.addEventListener('animationcancel', removeRipple, { once: true });

            const cat = pill.dataset.category as 'all' | Category;
            state.activeCategory =
                cat === state.activeCategory && cat !== 'all' ? 'all' : cat;

            categoryFilters.querySelectorAll('.category-pill').forEach((p) => {
                const isActive = (p as HTMLElement).dataset.category === state.activeCategory;
                p.classList.toggle('active', isActive);
                p.setAttribute('aria-selected', String(isActive));
                p.setAttribute('tabindex', isActive ? '0' : '-1');
            });

            // Keep tabpanel label in sync with the active tab
            const activeId = `pill-${state.activeCategory}`;
            document.getElementById('appGrid')?.setAttribute('aria-labelledby', activeId);

            filterAndSortApps();
        });

        categoryFilters.addEventListener('keydown', (e) => {
            if (e.key === 'ArrowRight' || e.key === 'ArrowLeft') {
                e.preventDefault();
                const pills = Array.from(categoryFilters.querySelectorAll('.category-pill'));
                const current = pills.indexOf(document.activeElement as Element);
                if (current === -1) return;
                const next =
                    e.key === 'ArrowRight'
                        ? Math.min(current + 1, pills.length - 1)
                        : Math.max(current - 1, 0);
                (pills[next] as HTMLElement).focus();
            }
        });
    }

    // Sort controls
    const sortRecent = document.getElementById('sortRecent');
    const sortAlpha = document.getElementById('sortAlpha');

    function activateSort(mode: 'recent' | 'alpha'): void {
        state.sortMode = mode;
        sortRecent?.classList.toggle('active', mode === 'recent');
        sortRecent?.setAttribute('aria-pressed', String(mode === 'recent'));
        sortAlpha?.classList.toggle('active', mode === 'alpha');
        sortAlpha?.setAttribute('aria-pressed', String(mode === 'alpha'));
        filterAndSortApps();
    }

    sortRecent?.addEventListener('click', () => activateSort('recent'));
    sortAlpha?.addEventListener('click', () => activateSort('alpha'));

    // CTA buttons
    document.getElementById('btn-trollapps')?.addEventListener('click', () => {
        window.location.href = `trollapps://add?url=${encodeURIComponent(CONFIG.API_ENDPOINT)}`;
    });
    document.getElementById('btn-sidestore')?.addEventListener('click', () => {
        window.location.href = `sidestore://source?url=${encodeURIComponent(CONFIG.API_ENDPOINT)}`;
    });

    // Copy URL
    document.getElementById('btn-copy-url')?.addEventListener('click', handleCopyUrl);

    // Cache reset — two-step confirmation via toast (avoids blocking window.confirm)
    document.getElementById('btn-reset')?.addEventListener('click', () => {
        showToast('Clear all local cache and data?', 'warning', {
            text: 'CLEAR',
            callback: () => { void clearAllCaches(); },
        });
    });

    // UX-004: footer Shortcuts button — makes the ? shortcut discoverable
    document.getElementById('btn-shortcuts')?.addEventListener('click', openShortcutsPanel);
}

