// ============================================================
// Mini's IPA Repo — App Card Renderer
// ============================================================
// iOS App Store–style cells: 64px icon, name + dev stacked right,
// tint accent bar, GET pill button, version badge.

import type { AppData } from './types';
import { CONFIG } from './config';
import { hexToRgba, isValidDownloadUrl, formatRelativeTime, escapeAttr } from './utils';
import { highlightMatches } from './search';
import { showToast } from './toast';

// Memoize tint color rgba variants — avoids recomputing hex→rgba on every card recycle.
// Capped at CONFIG.TINT_CACHE_MAX entries; oldest entry is evicted when the limit is reached.
// 007: the Map is declared with a fixed max so the eviction in getTintVariants is always
// exercised — no need for a separate batch-eviction mechanism on top of the per-insert guard.
const _tintCache = new Map<string, { t10: string; t20: string; t40: string; tb12: string }>();

// PERF-005: deduplicate icon preload warnings to avoid flooding the console on CDN outages.
// Tracks the set of hostnames for which we have already logged a failure this session.
const _warnedIconDomains = new Set<string>();

function getTintVariants(hex: string) {
    let v = _tintCache.get(hex);
    if (!v) {
        if (_tintCache.size >= CONFIG.TINT_CACHE_MAX) {
            // Map iterates in insertion order — delete the oldest key.
            _tintCache.delete(_tintCache.keys().next().value!);
        }
        v = {
            t10: hexToRgba(hex, 0.1),
            t20: hexToRgba(hex, 0.2),
            t40: hexToRgba(hex, 0.4),
            tb12: hexToRgba(hex, 0.12),
        };
        _tintCache.set(hex, v);
    }
    return v;
}

/**
 * Returns the tint color to use for the GET button text/border.
 * Black (#000000) is invisible on dark card backgrounds, so flip to white.
 */
function getButtonTintColor(tintColor: string): string {
    return tintColor.toUpperCase() === '#000000' ? '#FFFFFF' : tintColor;
}

/** Create an empty card DOM node for the virtual scroll pool */
export function createCardNode(): HTMLElement {
    const el = document.createElement('article');
    el.className = 'app-card';
    el.tabIndex = 0;
    el.innerHTML = `
        <div class="card-accent" aria-hidden="true"></div>
        <div class="card-body">
            <div class="card-icon-wrap">
                <img class="card-icon" width="64" height="64" loading="lazy" decoding="async" alt="">
                <span class="card-version-badge" aria-hidden="true"></span>
            </div>
            <div class="card-info">
                <h3 class="card-name"></h3>
                <p class="card-developer"></p>
                <p class="card-meta"></p>
            </div>
            <button type="button" class="card-get-btn" aria-label="">
                <span class="card-get-text">GET</span>
                <span class="card-get-spinner" aria-hidden="true"></span>
                <span class="card-get-check" aria-hidden="true"></span>
            </button>
        </div>
        <div class="card-separator" aria-hidden="true"></div>
    `;
    return el;
}

/** Bind app data to a card DOM node (recycled from pool) */
export function bindCard(
    el: HTMLElement,
    app: AppData,
    nameHighlightRanges?: [number, number][],
): void {
    el.dataset.appId = app.id;
    // A11Y-003: "activate" is device-agnostic (works for touch, mouse, and keyboard users)
    el.setAttribute('aria-label', `${escapeAttr(app.name)} by ${escapeAttr(app.developer)} — activate to view details`);

    // Tint color
    const tint = getTintVariants(app.tintColor);
    el.style.setProperty('--tint', app.tintColor);
    el.style.setProperty('--tint-10', tint.t10);
    el.style.setProperty('--tint-20', tint.t20);
    el.style.setProperty('--tint-40', tint.t40);

    // Accent bar
    const accent = el.querySelector('.card-accent') as HTMLElement;
    if (accent) accent.style.backgroundColor = app.tintColor;

    // Icon
    const img = el.querySelector('.card-icon') as HTMLImageElement;
    if (img) {
        // Normalize to absolute URL before comparing so that a relative path and its
        // absolute equivalent are never treated as different (fixes stale icons after
        // virtual-scroll node recycling when the same relative path is reused across apps).
        const resolvedIcon = new URL(app.icon, location.href).href;
        if (img.dataset.boundSrc !== resolvedIcon) {
            img.dataset.boundSrc = resolvedIcon;
            img.src = resolvedIcon;
            img.alt = `${app.name} icon`;
            img.onerror = () => {
                img.onerror = null; // Prevent infinite loop if fallback also fails
                img.src = CONFIG.FALLBACK_ICON;
            };
        }
    }

    // Version badge
    const vBadge = el.querySelector('.card-version-badge') as HTMLElement;
    if (vBadge) vBadge.textContent = `v${app.version}`;

    // Name (with optional search highlighting)
    const nameEl = el.querySelector('.card-name') as HTMLElement;
    if (nameEl) {
        if (nameHighlightRanges && nameHighlightRanges.length > 0) {
            nameEl.innerHTML = highlightMatches(app.name, nameHighlightRanges);
        } else {
            nameEl.textContent = app.name;
        }
    }

    // Developer
    const devEl = el.querySelector('.card-developer') as HTMLElement;
    if (devEl) devEl.textContent = app.developer;

    // Meta: size + date
    const metaEl = el.querySelector('.card-meta') as HTMLElement;
    if (metaEl) {
        metaEl.textContent = `${app.size} · ${formatRelativeTime(app.date)}`;
    }

    // GET button
    const btn = el.querySelector('.card-get-btn') as HTMLButtonElement;
    if (btn) {
        // Cancel any in-progress download animation before resetting button state.
        // A card can be recycled mid-animation (virtual scroll scrolls away), and
        // leaving the timer running would fight with bindCard's reset below.
        const existingTimer = _btnTimers.get(btn);
        if (existingTimer !== undefined) {
            clearTimeout(existingTimer);
            _btnTimers.delete(btn);
        }

        btn.dataset.id = app.id;
        btn.setAttribute('aria-label', `Download ${app.name}`);
        btn.className = 'card-get-btn';
        const btnTint = getButtonTintColor(app.tintColor);
        btn.style.setProperty('--btn-tint', btnTint);
        btn.style.setProperty('--btn-tint-bg', hexToRgba(btnTint, 0.12));

        // Reset button state
        const textEl = btn.querySelector('.card-get-text') as HTMLElement;
        if (textEl) textEl.style.display = '';
        const spinnerEl = btn.querySelector('.card-get-spinner') as HTMLElement;
        if (spinnerEl) spinnerEl.style.display = 'none';
        const checkEl = btn.querySelector('.card-get-check') as HTMLElement;
        if (checkEl) checkEl.style.display = 'none';
    }
}

/** Handle download button click with progress simulation */
export function handleDownload(appId: string, apps: AppData[], isOnline: boolean): void {
    const app = apps.find((a) => a.id === appId);
    if (!app) return;

    if (!isOnline) {
        showToast('You are offline. Downloads require a connection.', 'warning');
        return;
    }

    if (!isValidDownloadUrl(app.downloadUrl)) {
        showToast('Security Block: URL must be HTTPS', 'error');
        // UX-004: flash the GET button red so the user gets visual feedback
        const errBtn = document.querySelector(
            `.card-get-btn[data-id="${CSS.escape(appId)}"]`,
        ) as HTMLElement | null;
        if (errBtn) {
            errBtn.classList.add('download-error');
            setTimeout(() => errBtn.classList.remove('download-error'), CONFIG.BTN_ERROR_FLASH_DURATION);
        }
        return;
    }

    // Animate the button: GET → spinner → checkmark
    const btn = document.querySelector(
        `.card-get-btn[data-id="${CSS.escape(appId)}"]`,
    ) as HTMLElement | null;

    if (btn) {
        animateDownloadButton(btn);
    }

    // Trigger download
    const link = document.createElement('a');
    link.href = app.downloadUrl;
    link.target = '_blank';
    link.rel = 'noopener noreferrer';
    link.style.display = 'none';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);

    showToast(`Downloading ${app.name}`, 'success');
}

// Per-button timer tracking to prevent overlapping animations on rapid clicks.
const _btnTimers = new WeakMap<HTMLElement, ReturnType<typeof setTimeout>>();

/** Download button micro-interaction: GET → spinner → check */
function animateDownloadButton(btn: HTMLElement): void {
    const text = btn.querySelector('.card-get-text') as HTMLElement;
    const spinner = btn.querySelector('.card-get-spinner') as HTMLElement;
    const check = btn.querySelector('.card-get-check') as HTMLElement;

    if (!text || !spinner || !check) return;

    // Cancel any in-progress animation for this button before starting a new one.
    const existing = _btnTimers.get(btn);
    if (existing !== undefined) {
        clearTimeout(existing);
        _btnTimers.delete(btn);
    }

    // Skip micro-interaction for users who prefer no motion; just show check immediately.
    if (window.matchMedia('(prefers-reduced-motion: reduce)').matches) {
        btn.classList.add('downloaded');
        text.style.display = 'none';
        spinner.style.display = 'none';
        check.style.display = '';
        const t = setTimeout(() => {
            _btnTimers.delete(btn);
            btn.classList.remove('downloaded');
            text.style.display = '';
            check.style.display = 'none';
        }, CONFIG.BTN_CHECK_REDUCED_DURATION);
        _btnTimers.set(btn, t);
        return;
    }

    btn.classList.remove('downloaded');
    btn.classList.add('downloading');
    text.style.display = 'none';
    spinner.style.display = '';
    check.style.display = 'none';

    const t1 = setTimeout(() => {
        spinner.style.display = 'none';
        check.style.display = '';
        btn.classList.remove('downloading');
        btn.classList.add('downloaded');

        const t2 = setTimeout(() => {
            _btnTimers.delete(btn);
            btn.classList.remove('downloaded');
            text.style.display = '';
            check.style.display = 'none';
        }, CONFIG.BTN_CHECK_DURATION);
        _btnTimers.set(btn, t2);
    }, CONFIG.BTN_SPINNER_DURATION);
    _btnTimers.set(btn, t1);
}

// AbortController for the featured card's event listeners — replaced on each call.
let _featuredCardAbort: AbortController | null = null;

/** Create the featured app card content */
export function setupFeaturedCard(
    app: AppData,
    section: HTMLElement,
    card: HTMLElement,
    onOpen: (id: string) => void,
): void {
    const icon = card.querySelector('.featured-icon') as HTMLImageElement;
    const name = card.querySelector('.featured-name') as HTMLElement;
    const dev = card.querySelector('.featured-dev') as HTMLElement;
    const desc = card.querySelector('.featured-desc') as HTMLElement;
    const getBtn = card.querySelector('.featured-get-btn') as HTMLButtonElement;

    if (icon) {
        icon.src = app.icon;
        icon.alt = `${app.name} icon`;
        icon.onerror = () => {
            icon.onerror = null; // Prevent infinite loop if fallback also fails
            icon.src = CONFIG.FALLBACK_ICON;
        };
    }
    if (name) name.textContent = app.name;
    if (dev) dev.textContent = app.developer;
    if (desc) desc.textContent = app.description;

    // Apply tint
    const tint = getTintVariants(app.tintColor);

    if (getBtn) {
        getBtn.dataset.id = app.id;
        getBtn.setAttribute('aria-label', `Download ${app.name}`);
        const featBtnTint = getButtonTintColor(app.tintColor);
        getBtn.style.setProperty('--btn-tint', featBtnTint);
        getBtn.style.setProperty('--btn-tint-bg', hexToRgba(featBtnTint, 0.12));
    }
    card.style.setProperty('--tint', app.tintColor);
    card.style.setProperty('--tint-10', tint.t10);
    card.style.setProperty('--tint-20', tint.t20);

    card.setAttribute('data-app-id', app.id);
    card.setAttribute('aria-label', `${escapeAttr(app.name)} — featured app, activate to view details`);

    section.removeAttribute('hidden');
    section.classList.add('visible');

    // Abort any listeners from a previous call (e.g. background data refresh)
    // before adding new ones, so they never accumulate.
    _featuredCardAbort?.abort();
    _featuredCardAbort = new AbortController();
    const { signal } = _featuredCardAbort;

    card.addEventListener('click', (e) => {
        if (!(e.target as HTMLElement).closest('button')) onOpen(app.id);
    }, { signal });
    card.addEventListener('keydown', (e) => {
        if (e.key === 'Enter' || e.key === ' ') {
            // Let native <button> elements (e.g., the GET button) handle their own
            // activation. Without this guard, pressing Space/Enter on the GET button
            // would both download (native) and open the modal (this handler).
            if ((e.target as HTMLElement).closest('button')) return;
            e.preventDefault();
            onOpen(app.id);
        }
    }, { signal });
}

/** Set up image loading priorities for above-fold and near-fold cards */
export function setupImagePriorities(apps: AppData[]): void {
    // Preconnect to image host (only once — guard against repeated calls)
    const preconnectHref = 'https://objects.githubusercontent.com';
    if (!document.head.querySelector(`link[rel="preconnect"][href="${preconnectHref}"]`)) {
        const link = document.createElement('link');
        link.rel = 'preconnect';
        link.href = preconnectHref;
        link.crossOrigin = 'anonymous';
        document.head.appendChild(link);
    }

    // 008: build Set of already-preloaded hrefs in one DOM scan rather than
    // calling querySelector() per app (O(n) DOM queries → O(1) Set lookups).
    const existingPreloads = new Set<string>();
    document.head.querySelectorAll<HTMLLinkElement>('link[rel="preload"][as="image"]').forEach((el) => {
        existingPreloads.add(el.href);
    });

    // Preload first 6 app icons (skip any that already have a pending preload link)
    const preloadCount = Math.min(6, apps.length);
    for (let i = 0; i < preloadCount; i++) {
        const href = apps[i].icon;
        // Resolve to absolute URL for consistent deduplication
        let absHref: string;
        try { absHref = new URL(href, location.href).href; } catch { continue; }
        if (existingPreloads.has(absHref)) continue;
        existingPreloads.add(absHref); // Prevent duplicates within this loop
        const preload = document.createElement('link');
        preload.rel = 'preload';
        preload.as = 'image';
        preload.href = href;
        if (i < 3) {
            preload.setAttribute('fetchpriority', 'high');
        }
        // Remove link after image is fetched to keep <head> clean.
        // LEAK-001: also remove after CONFIG.PRELOAD_TIMEOUT in case the load/error
        // event never fires (e.g. stalled connection).
        const cleanup = () => { clearTimeout(leakTimer); preload.remove(); };
        preload.addEventListener('load', cleanup, { once: true });
        preload.addEventListener('error', () => {
            // PERF-005/QC-005: warn on preload failure, but only once per hostname to
            // avoid flooding the console when an entire CDN is down.
            try {
                const host = new URL(href, location.href).hostname;
                if (!_warnedIconDomains.has(host)) {
                    _warnedIconDomains.add(host);
                    console.warn('[card] Icon preload failed (first failure for this domain):', href);
                }
            } catch {
                console.warn('[card] Icon preload failed:', href);
            }
            cleanup();
        }, { once: true });
        // 021: use CONFIG.PRELOAD_TIMEOUT instead of a hardcoded literal.
        const leakTimer = setTimeout(() => preload.remove(), CONFIG.PRELOAD_TIMEOUT);
        document.head.appendChild(preload);
    }
}
