// ============================================================
// Mini's IPA Repo — App Detail Modal
// ============================================================
// Bottom-sheet style modal with spring physics, screenshot carousel,
// parallax icon tilt, and share capabilities.

import type { AppData, AppState } from './types';
import { CONFIG } from './config';
import { escapeHtml, escapeAttr, hexToRgba, formatRelativeTime } from './utils';
import { showToast } from './toast';
import { handleDownload } from './card';

// SVG icons defined at module scope so the modal template and the copy-button
// reset handler share a single source of truth (L5 — eliminates duplication).
const COPY_SVG = `<svg width="16" height="16" viewBox="0 0 16 16" fill="none" aria-hidden="true"><path d="M6 6H4a2 2 0 00-2 2v4a2 2 0 002 2h4a2 2 0 002-2v-2" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"/><rect x="6" y="2" width="8" height="8" rx="2" stroke="currentColor" stroke-width="1.5"/></svg>`;
const CHECK_SVG = `<svg width="16" height="16" viewBox="0 0 16 16" fill="none" aria-hidden="true"><path d="M3 8l3 3 7-7" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg>`;

// 012: trusted screenshot hostnames — only allow known image CDN domains to
// prevent a compromised mini.json from injecting arbitrary HTTPS URLs.
const SCREENSHOT_ALLOWLIST = [
    'raw.githubusercontent.com',
    'objects.githubusercontent.com',
    'github.com',
    'user-images.githubusercontent.com',
];

let activeModal: HTMLElement | null = null;

export function openAppModal(
    appId: string,
    state: AppState,
    fromUrl = false,
): void {
    const app = state.apps.find((a) => a.id === appId);
    if (!app || state.modalOpen) return;

    state.modalOpen = true;
    state.modalScrollY = window.scrollY;
    state.lastOpenedCardId = appId;

    // Preload images
    preloadModalImages(app);

    // Remove any existing modal
    activeModal?.remove();

    updateHash(app.bundleId, fromUrl, state);

    // Darken theme color while modal is open
    const themeMeta = document.getElementById('themeColor') as HTMLMetaElement | null;
    if (themeMeta) themeMeta.content = '#0a0a0f';

    const modal = document.createElement('div');
    modal.id = 'appModal';
    modal.className = 'modal-overlay';
    modal.setAttribute('role', 'dialog');
    modal.setAttribute('aria-modal', 'true');
    modal.setAttribute('aria-label', `${escapeAttr(app.name)} details`);

    // 036: validate bundleId format before constructing fragment URLs. A valid
    // bundle ID uses reverse-DNS notation (e.g. com.example.app). Malformed IDs
    // (e.g. from a compromised mini.json) fall back to the sanitized app.id.
    const safeBundleId = /^[\w.-]+$/.test(app.bundleId) ? app.bundleId : app.id;

    // Pre-check whether the Web Share API can handle this app's data before rendering
    // the share button. navigator.canShare() is more accurate than the bare 'share' in
    // navigator check — on some desktop Chrome builds the API exists but rejects certain
    // data and the user would see a failure toast instead of no button at all.
    const shareUrl = `${CONFIG.BASE_URL}#app-${encodeURIComponent(safeBundleId)}`;
    let canNativeShare = false;
    if ('share' in navigator) {
        try {
            canNativeShare = !navigator.canShare || navigator.canShare({
                title: `${app.name} — Mini's Repo`,
                url: shareUrl,
            });
        } catch {
            // canShare itself threw (unexpected) — fall back to showing the button
            canNativeShare = true;
        }
    }

    // 012/Sec3: only render screenshots from trusted HTTPS hosts to prevent
    // mixed-content and off-allowlist URLs (could be injected via a compromised mini.json).
    const safeScreenshots = app.screenshots.filter((url) => {
        try {
            const parsed = new URL(url);
            return parsed.protocol === 'https:' &&
                SCREENSHOT_ALLOWLIST.some((h) => parsed.hostname === h || parsed.hostname.endsWith('.' + h));
        } catch { return false; }
    });

    const screenshotsHtml =
        safeScreenshots.length > 0
            ? `<div class="modal-screenshots" role="region" aria-label="Screenshots">
                <div class="modal-screenshots-track">
                    ${safeScreenshots.map((url, i) => `<img src="${escapeAttr(url)}" alt="${escapeAttr(app.name)} screenshot ${i + 1}" loading="eager" decoding="async" class="modal-screenshot">`).join('')}
                </div>
                <div class="modal-dots" aria-hidden="true">
                    ${safeScreenshots.map((_, i) => `<span class="modal-dot${i === 0 ? ' active' : ''}"></span>`).join('')}
                </div>
            </div>`
            : '';

    const permissionsHtml =
        app.permissions.length > 0
            ? `<div class="modal-permissions">
                <span class="modal-permissions-label">Permissions:</span>
                ${app.permissions.map((p) => `<span class="modal-perm-tag" tabindex="0" title="${escapeAttr(p.usageDescription)}" aria-label="${escapeAttr(p.type)}: ${escapeAttr(p.usageDescription)}">${escapeHtml(p.type)}</span>`).join('')}
            </div>`
            : '';

    const changelogHtml = app.changelog
        ? `<div class="modal-changelog">
            <strong>What's New</strong>
            <p>${escapeHtml(app.changelog)}</p>
        </div>`
        : '';

    // "More by developer" — O(1) lookup via pre-built index (keys are lowercased)
    const moreByDev = (state.developerIndex?.get(app.developer.toLowerCase()) ?? [])
        .filter((a) => a.id !== app.id);
    const moreByDevHtml =
        moreByDev.length > 0
            ? `<div class="modal-more-section">
                <h4>More by ${escapeHtml(app.developer)}</h4>
                <div class="modal-more-row">
                    ${moreByDev.map((a) => `<button type="button" class="modal-more-item" data-app-id="${escapeAttr(a.id)}" aria-label="View ${escapeAttr(a.name)}">
                            <img src="${escapeAttr(a.icon)}" alt="" width="48" height="48" loading="lazy" decoding="async" class="modal-more-icon">
                            <span class="modal-more-name">${escapeHtml(a.name)}</span>
                        </button>`).join('')}
                </div>
            </div>`
            : '';

    modal.innerHTML = `
        <div class="modal-backdrop"></div>
        <div class="modal-content" role="document">
            <div class="modal-drag-handle" role="button" tabindex="0" aria-label="Dismiss dialog — drag down, or press Enter or Space"></div>
            <button type="button" class="modal-close" aria-label="Close dialog">
                <svg width="16" height="16" viewBox="0 0 16 16" fill="none"><path d="M4 4l8 8M12 4l-8 8" stroke="currentColor" stroke-width="2" stroke-linecap="round"/></svg>
            </button>
            <div class="modal-header">
                <div class="modal-icon-container">
                    <img src="${escapeAttr(app.icon)}" alt="${escapeAttr(app.name)} icon"
                         class="modal-icon" width="88" height="88">
                </div>
                <div class="modal-title-block">
                    <h2 class="modal-title">${escapeHtml(app.name)}</h2>
                    <p class="modal-developer">${escapeHtml(app.developer)}</p>
                    <div class="modal-meta">
                        <span class="modal-meta-item">v${escapeHtml(app.version)}</span>
                        <span class="modal-meta-sep" aria-hidden="true">&bull;</span>
                        <span class="modal-meta-item">${escapeHtml(app.size)}</span>
                        <span class="modal-meta-sep" aria-hidden="true">&bull;</span>
                        <span class="modal-meta-item">iOS ${escapeHtml(app.minimumOS)}+</span>
                    </div>
                </div>
            </div>
            ${screenshotsHtml}
            <div class="modal-body">
                <p class="modal-description">${escapeHtml(app.description)}</p>
                ${changelogHtml}
                ${permissionsHtml}
                <p class="modal-date">Updated ${escapeHtml(formatRelativeTime(app.date) || app.date)}</p>
            </div>
            ${moreByDevHtml}
            <div class="modal-footer">
                <div class="modal-action-row">
                    ${canNativeShare ? `<button type="button" class="modal-action-btn modal-share-btn" aria-label="Share ${escapeAttr(app.name)}">
                        <svg width="16" height="16" viewBox="0 0 16 16" fill="none"><path d="M8 2v8M4 6l4-4 4 4" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/><path d="M2 10v3a1 1 0 001 1h10a1 1 0 001-1v-3" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"/></svg>
                        Share
                    </button>` : ''}
                    <button type="button" class="modal-action-btn modal-copy-btn" aria-label="Copy link to ${escapeAttr(app.name)}">
                        ${COPY_SVG} Copy Link
                    </button>
                </div>
                <button type="button" class="modal-download-btn" data-id="${escapeAttr(app.id)}" aria-label="Download ${escapeAttr(app.name)} IPA">
                    Download IPA
                </button>
            </div>
        </div>
    `;

    document.body.appendChild(modal);
    activeModal = modal;

    // Apply tint glow
    const content = modal.querySelector('.modal-content') as HTMLElement;
    if (content) {
        content.style.setProperty('--modal-tint', app.tintColor);
        content.style.setProperty('--modal-tint-glow', hexToRgba(app.tintColor, 0.12));
    }

    // Icon error fallback: try FALLBACK_ICON first; if that also fails apply a
    // placeholder class (I3) so the header layout doesn't shift — the container
    // retains its size and shows a neutral background instead of collapsing.
    const modalIcon = modal.querySelector('.modal-icon') as HTMLImageElement;
    if (modalIcon) {
        modalIcon.addEventListener('error', () => {
            modalIcon.src = CONFIG.FALLBACK_ICON;
            modalIcon.alt = 'App icon';
            modalIcon.addEventListener('error', () => {
                modalIcon.style.display = 'none';
                const container = modalIcon.closest('.modal-icon-container');
                if (container) container.classList.add('modal-icon-missing');
            }, { once: true });
        }, { once: true });
    }

    // Screenshot error handling — remove failed images and their dots so the
    // carousel index stays in sync with the visible screenshot count.
    //
    // We capture the live position of the screenshot at error time rather than
    // relying on the pre-rendered data-idx attribute. If earlier screenshots
    // have already been removed and their dots deleted, the live index correctly
    // maps the failing img to its matching dot regardless of removal order.
    modal.querySelectorAll<HTMLElement>('.modal-screenshot').forEach((img) => {
        img.addEventListener('error', () => {
            const track = modal.querySelector('.modal-screenshots-track');
            const liveIdx = track
                ? Array.from(track.querySelectorAll('.modal-screenshot')).indexOf(img)
                : -1;
            img.remove();
            // 028: after removal, clamp the carousel scroll position so the user
            // doesn't see blank space where the failed screenshot used to be.
            if (track) {
                const remaining = track.querySelectorAll('.modal-screenshot');
                const trackEl = track as HTMLElement;
                const w = trackEl.offsetWidth;
                if (remaining.length > 0 && w > 0) {
                    const maxScroll = (remaining.length - 1) * w;
                    if (trackEl.scrollLeft > maxScroll) {
                        trackEl.scrollTo({ left: maxScroll, behavior: 'instant' });
                    }
                }
            }
            const dotsContainer = modal.querySelector('.modal-dots');
            if (dotsContainer) {
                if (liveIdx >= 0) {
                    dotsContainer.querySelectorAll('.modal-dot')[liveIdx]?.remove();
                }
                // Hide the dot row when ≤1 screenshot remains
                if (dotsContainer.querySelectorAll('.modal-dot').length <= 1) {
                    (dotsContainer as HTMLElement).style.display = 'none';
                }
            }
        }, { once: true });
    });

    // Lock body scroll
    document.body.classList.add('modal-open');
    document.body.style.top = `-${state.modalScrollY}px`;

    const closeBtn = modal.querySelector('.modal-close') as HTMLElement | null;

    // Trigger enter animation using rAF — avoids forced synchronous layout
    // (offsetHeight reflow) by deferring the class toggle to the next paint cycle.
    requestAnimationFrame(() => {
        modal.classList.add('active');
        // Focus close button after the transition class is applied so the
        // focus ring appears inside the animated element, not before it moves.
        closeBtn?.focus();
    });

    // Setup screenshot carousel and swipe-to-dismiss
    setupCarousel(modal);
    setupSwipeToDismiss(modal, state);

    // Event listeners
    modal.querySelector('.modal-backdrop')?.addEventListener('click', () => closeAppModal(false, state));
    closeBtn?.addEventListener('click', () => closeAppModal(false, state));

    modal.querySelector('.modal-download-btn')?.addEventListener('click', () => {
        handleDownload(app.id, state.apps, state.isOnline);
    });

    // Share button
    modal.querySelector('.modal-share-btn')?.addEventListener('click', async () => {
        const appUrl = `${CONFIG.BASE_URL}#app-${encodeURIComponent(safeBundleId)}`;
        try {
            await navigator.share({
                title: `${app.name} — Mini's Repo`,
                text: `Get ${app.name} (v${app.version}) from Mini's IPA Repo`,
                url: appUrl,
            });
        } catch (err) {
            // ERR-003: check for DOMException specifically — AbortError is thrown
            // when the user cancels the share sheet (normal UX, not an error).
            if (err instanceof DOMException && err.name === 'AbortError') return;
            // 002: NotAllowedError means the OS/browser denied share permission —
            // give a more actionable message so the user knows to check settings.
            if (err instanceof DOMException && err.name === 'NotAllowedError') {
                showToast('Share permission denied', 'warning');
                return;
            }
            showToast('Share failed', 'warning');
        }
    });

    // Copy link button
    const copyBtn = modal.querySelector('.modal-copy-btn');
    let copyResetTimer: ReturnType<typeof setTimeout> | null = null;
    copyBtn?.addEventListener('click', async () => {
        const appUrl = `${CONFIG.BASE_URL}#app-${encodeURIComponent(safeBundleId)}`;
        let copied = false;
        try {
            await navigator.clipboard.writeText(appUrl);
            copied = true;
        } catch {
            copied = fallbackCopy(appUrl);
        }
        if (copied) {
            (copyBtn as HTMLElement).classList.add('copied');
            (copyBtn as HTMLElement).innerHTML = `${CHECK_SVG} Copied!`;
            showToast('Link copied to clipboard', 'success');
            if (copyResetTimer !== null) clearTimeout(copyResetTimer);
            copyResetTimer = setTimeout(() => {
                copyResetTimer = null;
                (copyBtn as HTMLElement).classList.remove('copied');
                (copyBtn as HTMLElement).innerHTML = `${COPY_SVG} Copy Link`;
            }, CONFIG.COPY_RESET_DURATION);
        } else {
            showToast('Failed to copy link', 'warning');
        }
    });

    // "More by developer" clicks
    modal.querySelectorAll('.modal-more-item').forEach((btn) => {
        btn.addEventListener('click', () => {
            const targetId = (btn as HTMLElement).dataset.appId;
            if (targetId) {
                closeAppModal(false, state);
                setTimeout(() => openAppModal(targetId, state), CONFIG.MODAL_MORE_DELAY);
            }
        });
    });

    // Focus trap + keyboard
    modal.addEventListener('keydown', (e) => {
        if (e.key === 'Escape') {
            e.stopPropagation();
            closeAppModal(false, state);
            return;
        }
        if (e.key === 'Tab') trapFocus(e, modal);
    });
}

export function closeAppModal(viaPopstate: boolean, state: AppState): void {
    const modal = activeModal;
    if (!modal || !state.modalOpen) return;

    state.modalOpen = false;
    const wasSwipeOut = !!(modal as HTMLElement & { __swipeOut?: boolean }).__swipeOut;
    if (!wasSwipeOut) modal.classList.remove('active');

    // Restore theme color
    const themeMeta = document.getElementById('themeColor') as HTMLMetaElement | null;
    if (themeMeta) themeMeta.content = '#000000';

    document.body.classList.remove('modal-open');
    document.body.style.top = '';
    window.scrollTo({ top: state.modalScrollY, behavior: 'instant' as ScrollBehavior });

    if (!viaPopstate && state.modalHistoryPushed) {
        state.modalHistoryPushed = false;
        history.back();
    } else {
        state.modalHistoryPushed = false;
        updateHash(null, false, state);
    }

    const cardId = state.lastOpenedCardId;
    state.lastOpenedCardId = null;

    // 350ms > content transition (0.3s) and overlay transition (0.32s)
    const removeDelay = (modal as HTMLElement & { __swipeOut?: boolean }).__swipeOut ? 50 : 350;
    setTimeout(() => {
        modal.remove();
        // Only clear activeModal if it still points to this modal — a new modal
        // may have been opened before this timeout fires (close → immediate open),
        // in which case clearing unconditionally would orphan the new modal.
        if (activeModal === modal) activeModal = null;
    }, removeDelay);

    // Restore focus: to the card that opened the modal if it is still in the DOM
    // (category switches recycle cards), otherwise fall back to body.
    const card = cardId
        ? (document.querySelector(`.app-card[data-app-id="${CSS.escape(cardId)}"]`) as HTMLElement | null)
        : null;
    const focusTarget = (card && document.contains(card)) ? card : document.body;
    focusTarget.focus({ preventScroll: true });
}

// ── Hash Routing ───────────────────────────────────────────

function updateHash(bundleId: string | null, fromUrl: boolean, state: AppState): void {
    if (bundleId) {
        const hash = `#app-${encodeURIComponent(bundleId)}`;
        if (fromUrl) {
            history.replaceState({ appModal: true }, '', hash);
            state.modalHistoryPushed = false;
        } else {
            history.pushState({ appModal: true }, '', hash);
            state.modalHistoryPushed = true;
        }
    } else {
        history.replaceState(null, '', window.location.pathname + window.location.search);
    }
}

export function handleHashRoute(state: AppState): void {
    const hash = window.location.hash;
    if (hash && hash.startsWith('#app-')) {
        const bundleId = decodeURIComponent(hash.substring(5));
        const bundleIdLower = bundleId.toLowerCase();
        const app = state.apps.find((a) => a.bundleId === bundleId || a.id === bundleIdLower);
        if (app) {
            // CONFIG.HASH_ROUTE_DELAY lets initVirtualScroll() and filterAndSortApps()
            // finish their synchronous setup before the modal locks body scroll and
            // pushes history state — avoids a layout thrash on first paint.
            setTimeout(() => openAppModal(app.id, state, true), CONFIG.HASH_ROUTE_DELAY);
        }
    }
}

export function setupPopstateHandler(state: AppState): void {
    window.addEventListener('popstate', () => {
        if (state.modalOpen && !window.location.hash) {
            state.modalHistoryPushed = false;
            closeAppModal(true, state);
        } else if (window.location.hash?.startsWith('#app-')) {
            handleHashRoute(state);
        }
    });
}

// ── Screenshot Carousel ────────────────────────────────────

function setupCarousel(modal: HTMLElement): void {
    const track = modal.querySelector('.modal-screenshots-track') as HTMLElement;
    const dotsContainer = modal.querySelector('.modal-dots') as HTMLElement | null;
    if (!track || !dotsContainer) return;

    // Cache the dots array. A MutationObserver keeps it up-to-date whenever a
    // screenshot error handler removes a dot from the container — so the scroll
    // handler never has to re-query the DOM on every scroll event.
    let dots: Element[] = Array.from(dotsContainer.querySelectorAll('.modal-dot'));
    if (dots.length === 0) return;

    const dotsObserver = new MutationObserver(() => {
        dots = Array.from(dotsContainer.querySelectorAll('.modal-dot'));
    });
    dotsObserver.observe(dotsContainer, { childList: true });

    const wrapper = track.parentElement;
    if (!wrapper) return;

    // Make carousel keyboard-accessible (wrapper holds tabindex for focus)
    wrapper.setAttribute('tabindex', '0');
    wrapper.setAttribute('role', 'region');
    wrapper.setAttribute('aria-roledescription', 'carousel');
    // 016: mention all navigation methods so keyboard, touch, and mouse users
    // know how to interact with the carousel.
    wrapper.setAttribute('aria-label', 'Screenshots — swipe or use arrow keys to navigate');

    const images = track.querySelectorAll<HTMLElement>('.modal-screenshot');
    if (images.length === 0) { dotsObserver.disconnect(); return; }

    // Visually-hidden live region so screen readers announce slide changes.
    const srStatus = document.createElement('span');
    srStatus.className = 'visually-hidden';
    srStatus.setAttribute('aria-live', 'polite');
    srStatus.setAttribute('aria-atomic', 'true');
    wrapper.appendChild(srStatus);

    // Each screenshot is flex: 0 0 100% so the scroll unit is always the track width.
    // Reading track.offsetWidth at call time handles resize correctly.
    const getW = (): number => track.offsetWidth;

    let currentIndex = 0;

    const updateDots = (index: number) => {
        currentIndex = index;
        // Use the cached array — updated by MutationObserver, no DOM query per frame.
        dots.forEach((dot, i) => {
            dot.classList.toggle('active', i === currentIndex);
        });
        srStatus.textContent = `Screenshot ${currentIndex + 1} of ${dots.length}`;
    };

    // I2: sync dot indicator on both 'scroll' (for responsiveness) and 'scrollend'
    // (for accuracy after snap/smooth scroll settles). 'scrollend' is the
    // authoritative final position; 'scroll' gives immediate visual feedback.
    const onScrollSettle = () => {
        const w = getW();
        if (!w) return;
        const newIndex = Math.round(track.scrollLeft / w);
        if (newIndex !== currentIndex) updateDots(newIndex);
    };

    track.addEventListener('scroll', onScrollSettle, { passive: true });
    // 'scrollend' fires once scroll animation finishes (Chrome 114+, Firefox 109+)
    track.addEventListener('scrollend', onScrollSettle, { passive: true });

    // Keyboard navigation
    wrapper.addEventListener('keydown', (e: KeyboardEvent) => {
        if (e.key !== 'ArrowLeft' && e.key !== 'ArrowRight') return;
        e.preventDefault();
        const w = getW();
        if (!w) return;
        currentIndex = e.key === 'ArrowRight'
            ? Math.min(currentIndex + 1, images.length - 1)
            : Math.max(currentIndex - 1, 0);
        track.scrollTo({ left: currentIndex * w, behavior: 'smooth' });
        updateDots(currentIndex);
    });
}

// ── Swipe-to-Dismiss ───────────────────────────────────────

// Named thresholds for swipe-to-dismiss gesture recognition.
const DRAG_DISMISS_THRESHOLD  = 160; // px — deliberate downward pull dismisses sheet
const DRAG_FLICK_MIN_DISTANCE =  48; // px — minimum travel required before a flick counts
const DRAG_FLICK_VELOCITY     = 0.55; // px/ms — minimum speed to trigger a flick dismiss
const DAMPEN_DISTANCE         = 300; // px — rubber-band asymptote (feels "heavy" past this)
const BACKDROP_FADE_DISTANCE  = 280; // px — dampened travel at which backdrop reaches 0 opacity

function setupSwipeToDismiss(modal: HTMLElement, state: AppState): void {
    const content = modal.querySelector('.modal-content') as HTMLElement | null;
    const backdrop = modal.querySelector('.modal-backdrop') as HTMLElement | null;
    if (!content || !backdrop) return;

    let startY = 0;
    let currentY = 0;
    let isDragging = false;
    let activeTouchId: number | null = null;
    // Sliding window for accurate flick velocity (last 80ms of moves)
    let recentMoves: Array<{ y: number; t: number }> = [];

    // Rubber-band damping — the sheet resists at larger distances so it never
    // feels like it's flying away. Asymptotes around DAMPEN_DISTANCE px of visual travel.
    const dampen = (dy: number): number => dy / (1 + dy / DAMPEN_DISTANCE);

    const start = (clientY: number) => {
        if (content.scrollTop > 4) return;
        isDragging = true;
        startY = clientY;
        currentY = clientY;
        recentMoves = [{ y: clientY, t: Date.now() }];
        content.classList.add('is-dragging');
    };

    const move = (clientY: number) => {
        if (!isDragging) return;
        // C2: re-check scrollTop on every move — the user may have scrolled after
        // touchstart, so a drag begun at scrollTop=0 can still be intercepted.
        if (content.scrollTop > 4) {
            isDragging = false;
            content.classList.remove('is-dragging');
            content.style.transition = 'transform 0.25s cubic-bezier(0.22,1,0.36,1)';
            content.style.transform = '';
            backdrop.style.transition = 'opacity 0.25s ease';
            backdrop.style.opacity = '';
            return;
        }
        const dy = clientY - startY;
        if (dy < 0) {
            // Upward motion — hand off to native scroll cleanly
            isDragging = false;
            content.classList.remove('is-dragging');
            content.style.transition = 'transform 0.25s cubic-bezier(0.22,1,0.36,1)';
            content.style.transform = '';
            backdrop.style.transition = 'opacity 0.25s ease';
            backdrop.style.opacity = '';
            return;
        }
        currentY = clientY;
        const now = Date.now();
        recentMoves.push({ y: clientY, t: now });
        // Trim to last 80ms so velocity reflects the recent flick, not the whole drag
        recentMoves = recentMoves.filter((m) => now - m.t < 80);

        const translated = dampen(dy);
        content.style.transform = `translateY(${translated}px)`;
        // Fade backdrop using the dampened distance so it doesn't go fully
        // transparent until the sheet has visually moved quite far (≈BACKDROP_FADE_DISTANCE px).
        backdrop.style.opacity = String(Math.max(0, 1 - translated / BACKDROP_FADE_DISTANCE));
    };

    const end = () => {
        if (!isDragging) return;
        isDragging = false;
        content.classList.remove('is-dragging');
        activeTouchId = null;

        const dy = currentY - startY;

        // Velocity from the recent-move window (px/ms, positive = downward)
        let velocity = 0;
        if (recentMoves.length >= 2) {
            const first = recentMoves[0];
            const last = recentMoves[recentMoves.length - 1];
            velocity = (last.y - first.y) / Math.max(last.t - first.t, 1);
        }

        // Two ways to dismiss:
        //   1. Large drag: finger travelled > DRAG_DISMISS_THRESHOLD (deliberate pull)
        //   2. Quick flick: fast enough AND dragged at least DRAG_FLICK_MIN_DISTANCE first
        //      (prevents a tiny accidental fast touch from closing the modal)
        const shouldDismiss = dy > DRAG_DISMISS_THRESHOLD || (velocity > DRAG_FLICK_VELOCITY && dy > DRAG_FLICK_MIN_DISTANCE);

        if (shouldDismiss) {
            (modal as HTMLElement & { __swipeOut?: boolean }).__swipeOut = true;
            content.style.transition = 'transform 0.28s cubic-bezier(0.4,0,1,1)';
            content.style.transform = 'translateY(100%)';
            backdrop.style.transition = 'opacity 0.28s ease';
            backdrop.style.opacity = '0';
            setTimeout(() => closeAppModal(false, state), 260);
        } else {
            // Smooth spring back — no overshoot bounce, just a clean deceleration
            content.style.transition = 'transform 0.3s cubic-bezier(0.22,1,0.36,1)';
            content.style.transform = '';
            backdrop.style.transition = 'opacity 0.32s ease';
            backdrop.style.opacity = '';
            // 039: clear inline transition strings exactly when the animation finishes
            // rather than after a hardcoded 350ms timeout.
            content.addEventListener('transitionend', () => {
                if (!isDragging) {
                    content.style.transition = '';
                    backdrop.style.transition = '';
                    backdrop.style.opacity = '';
                }
            }, { once: true });
        }
    };

    const cancel = () => {
        if (!isDragging) return;
        isDragging = false;
        activeTouchId = null;
        content.classList.remove('is-dragging');
        content.style.transition = 'transform 0.3s cubic-bezier(0.22,1,0.36,1)';
        content.style.transform = '';
        backdrop.style.transition = '';
        backdrop.style.opacity = '';
    };

    // Touch (mobile)
    content.addEventListener('touchstart', (e) => {
        if (activeTouchId !== null) return;
        const t = e.touches[0];
        activeTouchId = t.identifier;
        start(t.clientY);
    }, { passive: true });

    content.addEventListener('touchmove', (e) => {
        if (activeTouchId === null) return;
        const t = Array.from(e.touches).find((x) => x.identifier === activeTouchId);
        if (t) move(t.clientY);
    }, { passive: true });

    content.addEventListener('touchend', (e) => {
        if (!Array.from(e.touches).some((t) => t.identifier === activeTouchId)) end();
    }, { passive: true });

    content.addEventListener('touchcancel', cancel, { passive: true });

    // Mouse (desktop — drag handle only, so it doesn't fight with text selection)
    const handle = modal.querySelector('.modal-drag-handle') as HTMLElement | null;
    if (handle) {
        // A11Y-001: keyboard alternative for swipe-to-dismiss — Enter/Space on the
        // drag handle triggers dismiss so keyboard users can close the bottom sheet
        // without needing the Escape key (which may be harder to reach on mobile keyboards).
        handle.addEventListener('keydown', (e) => {
            if (e.key === 'Enter' || e.key === ' ') {
                e.preventDefault();
                closeAppModal(false, state);
            }
        });

        handle.addEventListener('mousedown', (e) => {
            start(e.clientY);
            const onMove = (ev: MouseEvent) => move(ev.clientY);
            const onUp = () => {
                end();
                window.removeEventListener('mousemove', onMove);
                window.removeEventListener('mouseup', onUp);
            };
            window.addEventListener('mousemove', onMove);
            window.addEventListener('mouseup', onUp);
        });
    }
}

// ── Utilities ──────────────────────────────────────────────

function preloadModalImages(app: AppData): void {
    // Clean up any stale preload links from previously opened modals
    document.querySelectorAll('link.modal-preload').forEach((el) => el.remove());

    const urls = [app.icon, ...app.screenshots].filter(Boolean);
    const existing = new Set<string>();
    document.querySelectorAll('link[rel="preload"][as="image"]').forEach((el) => {
        existing.add((el as HTMLLinkElement).href);
    });

    for (const url of urls) {
        let abs: string;
        try {
            abs = new URL(url, window.location.href).href;
        } catch {
            continue;
        }
        if (existing.has(abs)) continue;
        const link = document.createElement('link');
        link.rel = 'preload';
        link.as = 'image';
        link.href = url;
        link.className = 'modal-preload';
        document.head.appendChild(link);
        // LEAK-002: remove once fetched (or on error), and also after 30 s as a
        // safety net in case the load/error event never fires (stalled connection).
        const cleanup = () => { clearTimeout(leakTimer); link.remove(); };
        link.addEventListener('load', cleanup, { once: true });
        link.addEventListener('error', cleanup, { once: true });
        const leakTimer = setTimeout(() => link.remove(), 30_000);
    }
}

function trapFocus(e: KeyboardEvent, modal: HTMLElement): void {
    const focusable = modal.querySelectorAll<HTMLElement>(
        'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])',
    );
    if (focusable.length === 0) return;
    const first = focusable[0];
    const last = focusable[focusable.length - 1];

    if (e.shiftKey && document.activeElement === first) {
        e.preventDefault();
        last.focus();
    } else if (!e.shiftKey && document.activeElement === last) {
        e.preventDefault();
        first.focus();
    }
}

function fallbackCopy(text: string): boolean {
    try {
        const ta = document.createElement('textarea');
        ta.value = text;
        ta.style.cssText = 'position:fixed;left:-9999px;opacity:0';
        document.body.appendChild(ta);
        ta.select();
        const ok = document.execCommand('copy');
        document.body.removeChild(ta);
        return ok;
    } catch {
        return false;
    }
}
